INSERT INTO dados_financeiros (clienteId, remuneracaoBruta, remuneracaoLiquida, margemConsignavelValor, totalConsignacoes, margemExcedida, fonteRenda) 
SELECT c.id, 13049.00, 4515.00, 1852.00, 8534.00, 1, 'Militar - Estado de Goiás' FROM clientes c WHERE REPLACE(REPLACE(REPLACE(c.cpfCnpj, '.', ''), '-', ''), '/', '') = '04056581177'
ON DUPLICATE KEY UPDATE remuneracaoBruta = VALUES(remuneracaoBruta);

